export const notesRepo = {
  async listForOwner(ownerId: string) {
    return prisma.note.findMany({
      where: {
        ownerId
      },
      orderBy: {
        updatedAt: "desc"
      },
      select: {
        id: true,
        title: true,
        excerpt: true,
        isPublished: true,
        createdAt: true,
        updatedAt: true
      }
    });
  },
  async findByIdForOwner(ownerId: string, id: string) {
    return prisma.note.findFirst({
      where: {
        id,
        ownerId
      },
      select: {
        id: true,
        title: true,
        slug: true,
        markdown: true,
        excerpt: true,
        isPublished: true,
        createdAt: true,
        updatedAt: true
      }
    });
