  1	function escapeHtml(value: string) {
  2	  return value
  3	    .replaceAll("&", "&amp;")
  4	    .replaceAll("<", "&lt;")
  5	    .replaceAll(">", "&gt;")
  6	    .replaceAll('"', "&quot;")
  7	    .replaceAll("'", "&#39;");
