 32	function renderInlineMarkdown(markdown: string): string {
 33	  const pattern = /(`[^`]+`)|(\[([^\]]+)\]\(([^)]+)\))|(\*\*([^*]+)\*\*)|(\*([^*]+)\*)/g;
 34	  let result = "";
 35	  let cursor = 0;
 36	
 37	  for (const match of markdown.matchAll(pattern)) {
 38	    const matchedText = match[0];
 39	    const matchIndex = match.index ?? 0;
 40	
 41	    result += escapeHtml(markdown.slice(cursor, matchIndex));
 42	
 43	    if (match[1]) {
 44	      result += `<code>${escapeHtml(matchedText.slice(1, -1))}</code>`;
 45	    } else if (match[2]) {
 46	      result += `<a href="${escapeHtml(sanitizeUrl(match[4] ?? ""))}" rel="noreferrer noopener" target="_blank">${renderInlineMarkdown(match[3] ?? "")}</a>`;
 47	    } else if (match[5]) {
 48	      result += `<strong>${renderInlineMarkdown(match[6] ?? "")}</strong>`;
 49	    } else if (match[7]) {
 50	      result += `<em>${renderInlineMarkdown(match[8] ?? "")}</em>`;
 51	    }
 52	
 53	    cursor = matchIndex + matchedText.length;
 54	  }
 55	
 56	  result += escapeHtml(markdown.slice(cursor));
 57	
 58	  return result;
 59	}
