 69	function stripMarkdown(value: string) {
 70	  return value
 71	    .replace(/```[\s\S]*?```/g, " ")
 72	    .replace(/`([^`]+)`/g, "$1")
 73	    .replace(/\[([^\]]+)\]\(([^)]+)\)/g, "$1")
 74	    .replace(/[*_>#-]/g, " ")
 75	    .replace(/\d+\.\s+/g, " ")
 76	    .replace(/\s+/g, " ")
 77	    .trim();
 78	}
