 80	export function createNoteExcerpt(markdown: string, title: string, maxLength = 180) {
 81	  const text = stripMarkdown(markdown) || title.trim();
 82	
 83	  if (text.length <= maxLength) {
 84	    return text;
 85	  }
 86	
 87	  return `${text.slice(0, maxLength).trimEnd()}...`;
 88	}
