 90	export function renderMarkdownToHtml(markdown: string) {
 91	  const normalizedLines = markdown.replace(/\r\n?/g, "\n").split("\n");
 92	  const blocks: string[] = [];
 93	
 94	  for (let index = 0; index < normalizedLines.length; ) {
 95	    const line = normalizedLines[index];
 96	    const trimmedLine = line.trim();
 97	
 98	    if (!trimmedLine) {
 99	      index += 1;
100	      continue;
101	    }
102	
103	    if (trimmedLine.startsWith("```")) {
104	      const codeLines: string[] = [];
105	      index += 1;
106	
107	      while (index < normalizedLines.length && !normalizedLines[index].trim().startsWith("```")) {
108	        codeLines.push(normalizedLines[index]);
109	        index += 1;
110	      }
111	
112	      if (index < normalizedLines.length) {
113	        index += 1;
114	      }
115	
116	      blocks.push(`<pre><code>${escapeHtml(codeLines.join("\n"))}</code></pre>`);
117	      continue;
118	    }
119	
120	    const headingMatch = trimmedLine.match(/^(#{1,6})\s+(.*)$/);
121	
122	    if (headingMatch) {
123	      const level = headingMatch[1].length;
124	      blocks.push(`<h${level}>${renderInlineMarkdown(headingMatch[2])}</h${level}>`);
125	      index += 1;
126	      continue;
127	    }
128	
129	    if (/^---+$/.test(trimmedLine)) {
130	      blocks.push("<hr />");
131	      index += 1;
132	      continue;
133	    }
134	
135	    if (trimmedLine.startsWith(">")) {
136	      const quoteLines: string[] = [];
137	
138	      while (index < normalizedLines.length && normalizedLines[index].trim().startsWith(">")) {
139	        quoteLines.push(normalizedLines[index].replace(/^>\s?/, ""));
140	        index += 1;
141	      }
142	
143	      const quoteContent = quoteLines.map((quoteLine) => renderInlineMarkdown(quoteLine)).join("<br />");
144	      blocks.push(`<blockquote><p>${quoteContent}</p></blockquote>`);
145	      continue;
146	    }
147	
148	    if (isUnorderedListItem(trimmedLine)) {
149	      const items: string[] = [];
150	
151	      while (index < normalizedLines.length && isUnorderedListItem(normalizedLines[index].trim())) {
152	        items.push(`<li>${renderInlineMarkdown(normalizedLines[index].trim().replace(/^[-*]\s+/, ""))}</li>`);
153	        index += 1;
154	      }
155	
156	      blocks.push(`<ul>${items.join("")}</ul>`);
157	      continue;
158	    }
159	
160	    if (isOrderedListItem(trimmedLine)) {
161	      const items: string[] = [];
162	
163	      while (index < normalizedLines.length && isOrderedListItem(normalizedLines[index].trim())) {
164	        items.push(`<li>${renderInlineMarkdown(normalizedLines[index].trim().replace(/^\d+\.\s+/, ""))}</li>`);
165	        index += 1;
166	      }
167	
168	      blocks.push(`<ol>${items.join("")}</ol>`);
169	      continue;
170	    }
171	
172	    const paragraphLines: string[] = [];
173	
174	    while (index < normalizedLines.length) {
175	      const candidate = normalizedLines[index];
176	      const trimmedCandidate = candidate.trim();
177	
178	      if (!trimmedCandidate) {
179	        break;
180	      }
181	
182	      if (
183	        trimmedCandidate.startsWith("```") ||
184	        trimmedCandidate.startsWith(">") ||
185	        /^---+$/.test(trimmedCandidate) ||
186	        /^(#{1,6})\s+/.test(trimmedCandidate) ||
187	        isUnorderedListItem(trimmedCandidate) ||
188	        isOrderedListItem(trimmedCandidate)
189	      ) {
190	        break;
191	      }
192	
193	      paragraphLines.push(candidate);
194	      index += 1;
195	    }
196	
197	    const paragraphContent = paragraphLines.map((paragraphLine) => renderInlineMarkdown(paragraphLine)).join("<br />");
198	    blocks.push(`<p>${paragraphContent}</p>`);
199	  }
200	
201	  return blocks.join("\n");
202	}
